@namespace Lumeo

<div class="@RootClasses" @attributes="AdditionalAttributes">
    <div class="flex items-baseline justify-between gap-3">
        <div class="min-w-0">
            @if (!string.IsNullOrEmpty(Label))
            {
                <div class="@LabelClass">@Label</div>
            }
            @if (!string.IsNullOrEmpty(Value))
            {
                <div class="@ValueClass">@Value</div>
            }
        </div>
    </div>

    <div class="@SparklineHeightClass w-full">
        @if (ChildContent is not null)
        {
            @ChildContent
        }
        else if (_chartValues is not null)
        {
            @* #276: delegate to the full Sparkline so the inline chart is as
               capable (Type / Area / per-point tooltips) as the standalone
               component, instead of a hardcoded less-capable polyline. A single
               data point can't form a line, so the chart is only rendered for
               two or more points (matching the pre-#276 contract). *@
            <Sparkline Values="@_chartValues" Type="@Type" ShowArea="@ShowArea" ShowLast="@ShowLast"
                       ShowTooltips="@ShowTooltips" Color="@SparkColor" Height="@SparkHeight"
                       Class="h-full w-full" aria-hidden="true" />
        }
    </div>
</div>

@code {
    /// <summary>Small caption shown above the value (e.g. "Revenue"). Omitted entirely when blank.</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>The headline metric, rendered large and bold below the label. Omitted entirely when blank.</summary>
    [Parameter] public string? Value { get; set; }

    /// <summary>Numeric series rendered as an inline sparkline below the value. Needs at least two points to draw a line; anything shorter renders nothing. Ignored when <see cref="ChildContent"/> is supplied.</summary>
    [Parameter] public IEnumerable<double>? Data { get; set; }

    /// <summary>Custom content for the sparkline region, replacing the built-in chart driven by <see cref="Data"/>.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Controls padding, typography and sparkline height. Defaults to <see cref="Lumeo.Size.Md"/>.</summary>
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;

    /// <summary>Card surface style: <see cref="SparkCardVariant.Default"/> (standard border), <see cref="SparkCardVariant.Bordered"/> (thicker 2px border), or <see cref="SparkCardVariant.Filled"/> (muted background).</summary>
    [Parameter] public SparkCardVariant Variant { get; set; } = SparkCardVariant.Default;

    /// <summary>Inline sparkline shape (Line / Area / Bars). (#276)</summary>
    [Parameter] public Sparkline.SparkType Type { get; set; } = Sparkline.SparkType.Line;
    /// <summary>Fill the area under a line sparkline. (#276)</summary>
    [Parameter] public bool ShowArea { get; set; }
    /// <summary>Mark the most recent point. (#276)</summary>
    [Parameter] public bool ShowLast { get; set; }
    /// <summary>Per-point markers + hover tooltips on the inline sparkline. (#276)</summary>
    [Parameter] public bool ShowTooltips { get; set; }
    /// <summary>Override the sparkline color (CSS color / var). (#276)</summary>
    [Parameter] public string? SparkColor { get; set; }

    /// <summary>Additional CSS classes merged onto the root card.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures any unmatched attributes and applies them to the root card.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Materialized once per parameter set: the inline chart needs at least two
    // points to draw a line, so anything shorter renders nothing (no stray svg).
    private IReadOnlyList<double>? _chartValues;

    protected override void OnParametersSet()
    {
        var list = Data as IReadOnlyList<double> ?? Data?.ToList();
        _chartValues = list is { Count: >= 2 } ? list : null;
    }

    private int SparkHeight => Size switch
    {
        Lumeo.Size.Sm => 32,
        Lumeo.Size.Lg => 56,
        _ => 40
    };

    private string SizePadding => Size switch
    {
        Lumeo.Size.Sm => "p-3",
        Lumeo.Size.Lg => "p-6",
        _ => "p-5"
    };

    private string SparklineHeightClass => Size switch
    {
        Lumeo.Size.Sm => "mt-2 h-8",
        Lumeo.Size.Lg => "mt-4 h-14",
        _ => "mt-3 h-10"
    };

    private string LabelClass => Size switch
    {
        Lumeo.Size.Sm => "text-xs text-muted-foreground truncate",
        Lumeo.Size.Lg => "text-base text-muted-foreground truncate",
        _ => "text-sm text-muted-foreground truncate"
    };

    private string ValueClass => Size switch
    {
        Lumeo.Size.Sm => "mt-0.5 text-lg font-semibold tracking-tight text-foreground",
        Lumeo.Size.Lg => "mt-1.5 text-3xl font-semibold tracking-tight text-foreground",
        _ => "mt-1 text-2xl font-semibold tracking-tight text-foreground"
    };

    private string VariantClasses => Variant switch
    {
        SparkCardVariant.Bordered => "rounded-xl border-2 border-border/50 bg-card text-card-foreground",
        SparkCardVariant.Filled => "rounded-xl border border-border/40 bg-muted text-card-foreground",
        _ => "rounded-xl border border-border/40 bg-card text-card-foreground"
    };

    private string RootClasses =>
        Cx.Merge(VariantClasses, SizePadding, Class);

    /// <summary>
    /// Default = standard card border. Bordered = thicker 2px border. Filled = muted background.
    /// </summary>
    public enum SparkCardVariant { Default, Bordered, Filled }
}
